$ErrorActionPreference = "Stop"

$project = Join-Path $HOME "Desktop\whokeas-all-in"

if (-not (Test-Path (Join-Path $project "package.json"))) {
  throw "Project not found at $project"
}

$timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
$tempRoot = Join-Path $env:TEMP "whokeas-final-fix-$timestamp"
$tempZip = Join-Path $tempRoot "patch.zip"
$backupRoot = Join-Path $tempRoot "backup"
$backupZip = Join-Path ([Environment]::GetFolderPath("Desktop")) "WHOKEAS-before-final-fix-$timestamp.zip"

New-Item -ItemType Directory -Force $tempRoot | Out-Null
New-Item -ItemType Directory -Force $backupRoot | Out-Null

$changedFiles = @(
  ".env.example",
  "package.json",
  "src\app\globals.css",
  "src\app\layout.tsx",
  "src\app\page.tsx",
  "src\db\repair-catalog-final.ts",
  "src\db\schema.ts",
  "src\lib\catalog-schema.ts",
  "src\lib\cj-sync.ts",
  "src\lib\product-admin.ts",
  "src\lib\store-catalog.ts",
  "src\components\admin\CJConnectorClient.tsx",
  "src\components\admin\ProductControlClient.tsx",
  "src\components\checkout\CheckoutClient.tsx",
  "src\components\payments\PaymentReferenceForm.tsx",
  "src\components\store\AddToCart.tsx",
  "src\components\store\CartButton.tsx",
  "src\components\store\CartClient.tsx",
  "src\components\store\StoreHeader.tsx",
  "src\components\store\StoreProductCard.tsx",
  "src\app\cart\page.tsx",
  "src\app\checkout\page.tsx",
  "src\app\products\page.tsx",
  "src\app\products\[slug]\page.tsx",
  "src\app\order-confirmation\[orderNumber]\page.tsx",
  "src\app\api\admin\catalog-health\route.ts",
  "src\app\api\admin\products\[id]\route.ts",
  "src\app\api\admin\cj\import\route.ts",
  "src\app\admin\products\page.tsx"
)

foreach ($relative in $changedFiles) {
  $source = Join-Path $project $relative

  if (Test-Path -LiteralPath $source) {
    $destination = Join-Path $backupRoot $relative
    $parent = Split-Path -Parent $destination

    if ($parent) {
      New-Item -ItemType Directory -Force $parent | Out-Null
    }

    Copy-Item -LiteralPath $source -Destination $destination -Force
  }
}

if ((Get-ChildItem $backupRoot -Recurse -File -ErrorAction SilentlyContinue).Count -gt 0) {
  Compress-Archive -Path (Join-Path $backupRoot "*") -DestinationPath $backupZip -Force
  Write-Host "Backup created: $backupZip" -ForegroundColor DarkCyan
}

