[System.IO.File]::WriteAllBytes(
  $tempZip,
  [Convert]::FromBase64String(($base64 -replace "\s", ""))
)

Write-Host "Applying the final WHOKEAS source repair..." -ForegroundColor Cyan
Expand-Archive -LiteralPath $tempZip -DestinationPath $project -Force

Set-Location $project

Write-Host "Repairing the Neon catalogue..." -ForegroundColor Cyan
npm run catalog:repair

Write-Host "Clearing the old Next.js cache..." -ForegroundColor Cyan
Remove-Item -Recurse -Force ".\.next" -ErrorAction SilentlyContinue

Write-Host "Running the production build check..." -ForegroundColor Cyan
npm run build

Remove-Item -LiteralPath $tempRoot -Recurse -Force -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "WHOKEAS FINAL FIX INSTALLED SUCCESSFULLY." -ForegroundColor Green
Write-Host "Next run: npm run dev" -ForegroundColor Yellow
Write-Host "Then open: http://localhost:3000/api/admin/catalog-health" -ForegroundColor Cyan
Write-Host "Then open: http://localhost:3000/admin/cj" -ForegroundColor Cyan
Write-Host "Then open: http://localhost:3000/admin/products" -ForegroundColor Cyan
Write-Host "Customer storefront: http://localhost:3000" -ForegroundColor Cyan
